/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Formats notification payloads as short text messages and sends them
 * to a phone number. Uses an in-memory transport by default (suitable
 * for testing; swap the transport for production).
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** A rendered SMS message ready for delivery. */
export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

/** Options for configuring the SMS adapter. */
export interface SmsAdapterOptions {
  /** Sender phone number or short code shown in the From field. */
  fromNumber?: string;
  /** Maximum character length for SMS body. Messages are truncated if exceeded. */
  maxLength?: number;
  /**
   * Optional SMS transport function. When provided, the adapter calls this
   * instead of storing messages in memory. Return true for success, false for failure.
   */
  sendSms?: (to: string, body: string, from: string) => Promise<boolean>;
}

const PHONE_REGEX = /^\+?[1-9]\d{6,14}$/;

/**
 * Validate that a recipient string is a plausible phone number (E.164-ish).
 */
export function validatePhoneNumber(phone: string): { valid: boolean; error?: string } {
  if (!phone || phone.trim().length === 0) {
    return { valid: false, error: 'Phone number is empty' };
  }
  if (!PHONE_REGEX.test(phone)) {
    return { valid: false, error: `Invalid phone number: ${phone}` };
  }
  return { valid: true };
}

/**
 * Format a NotificationPayload into a short SMS text body.
 * SMS messages are short, so we combine subject and body into a concise format.
 */
export function formatSmsBody(payload: NotificationPayload, maxLength: number): string {
  const text = `${payload.subject}: ${payload.body}`;
  if (text.length <= maxLength) {
    return text;
  }
  return text.substring(0, maxLength - 3) + '...';
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private fromNumber: string;
  private maxLength: number;
  private sendSmsFn?: (to: string, body: string, from: string) => Promise<boolean>;

  constructor(options?: SmsAdapterOptions) {
    this.fromNumber = options?.fromNumber ?? '+10000000000';
    this.maxLength = options?.maxLength ?? 160;
    this.sendSmsFn = options?.sendSms;
  }

  /**
   * Send a notification as an SMS.
   * Validates the phone number, formats the message, and delivers it.
   * In production, provide a sendSms transport; otherwise messages are stored in memory.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate recipient phone number
      const validation = validatePhoneNumber(payload.recipient);
      if (!validation.valid) {
        this.logger.error(`Phone validation failed: ${validation.error}`);
        return {
          success: false,
          channel: this.channel,
          notificationId: payload.id,
          error: validation.error!,
          deliveredAt: new Date(),
        };
      }

      // Format SMS body
      const body = formatSmsBody(payload, this.maxLength);

      // Deliver via transport or store in memory
      if (this.sendSmsFn) {
        const success = await this.sendSmsFn(payload.recipient, body, this.fromNumber);
        if (!success) {
          this.logger.error(`SMS send failed for ${payload.recipient}`);
          return {
            success: false,
            channel: this.channel,
            notificationId: payload.id,
            error: `SMS send failed for ${payload.recipient}`,
            deliveredAt: new Date(),
          };
        }
      }

      const message: SmsMessage = {
        to: payload.recipient,
        body,
        sentAt: new Date(),
      };

      this.sentMessages.push(message);
      this.logger.info(`SMS delivered to ${payload.recipient}`);

      return {
        success: true,
        channel: this.channel,
        notificationId: payload.id,
        deliveredAt: message.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown SMS error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        notificationId: payload.id,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all sent messages. Useful for testing. */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /** Clear sent messages. Useful for testing. */
  clearSentMessages(): void {
    this.sentMessages = [];
  }

  /** Get the configured from number. */
  getFromNumber(): string {
    return this.fromNumber;
  }

  /** Get the configured max message length. */
  getMaxLength(): number {
    return this.maxLength;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsNotificationAdapter,
  validatePhoneNumber,
  formatSmsBody,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('validatePhoneNumber', () => {
  it('should accept a valid E.164 phone number', () => {
    expect(validatePhoneNumber('+15551234567')).toEqual({ valid: true });
  });

  it('should accept a number without + prefix', () => {
    expect(validatePhoneNumber('15551234567')).toEqual({ valid: true });
  });

  it('should reject an empty string', () => {
    const result = validatePhoneNumber('');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('empty');
  });

  it('should reject a string with letters', () => {
    const result = validatePhoneNumber('+1555abc4567');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid');
  });

  it('should reject a number that is too short', () => {
    const result = validatePhoneNumber('+12345');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid');
  });

  it('should reject a number starting with 0', () => {
    const result = validatePhoneNumber('0551234567');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid');
  });
});

describe('formatSmsBody', () => {
  it('should combine subject and body', () => {
    const payload = makePayload();
    const body = formatSmsBody(payload, 160);

    expect(body).toBe('Order Confirmation: order-1: Your order has been placed. Items: Widget x2. Total: $20.00');
  });

  it('should truncate long messages with ellipsis', () => {
    const payload = makePayload({
      subject: 'Order Confirmation',
      body: 'A'.repeat(200),
    });
    const body = formatSmsBody(payload, 160);

    expect(body.length).toBe(160);
    expect(body.endsWith('...')).toBe(true);
  });

  it('should not truncate messages within the limit', () => {
    const payload = makePayload({ subject: 'Hi', body: 'Done' });
    const body = formatSmsBody(payload, 160);

    expect(body).toBe('Hi: Done');
    expect(body.length).toBeLessThanOrEqual(160);
  });

  it('should respect custom max length', () => {
    const payload = makePayload({ subject: 'Test', body: 'A very long message that exceeds the limit' });
    const body = formatSmsBody(payload, 20);

    expect(body.length).toBe(20);
    expect(body.endsWith('...')).toBe(true);
  });
});

describe('SmsNotificationAdapter', () => {
  let adapter: SmsNotificationAdapter;

  beforeEach(() => {
    adapter = new SmsNotificationAdapter();
  });

  it('should have channel "sms"', () => {
    expect(adapter.channel).toBe('sms');
  });

  it('should use default config values', () => {
    expect(adapter.getFromNumber()).toBe('+10000000000');
    expect(adapter.getMaxLength()).toBe(160);
  });

  it('should accept custom options', () => {
    const custom = new SmsNotificationAdapter({
      fromNumber: '+18005551234',
      maxLength: 140,
    });
    expect(custom.getFromNumber()).toBe('+18005551234');
    expect(custom.getMaxLength()).toBe(140);
  });

  describe('send', () => {
    it('should deliver a valid notification and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store the sent message', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+15551234567');
      expect(messages[0]!.body).toContain('Order Confirmation');
      expect(messages[0]!.sentAt).toBeInstanceOf(Date);
    });

    it('should fail for invalid phone number', async () => {
      const payload = makePayload({ recipient: 'not-a-phone' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should fail for empty phone number', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ id: 'n1', recipient: '+15551111111' }));
      await adapter.send(makePayload({ id: 'n2', recipient: '+15552222222' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();

      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return defensive copy from getSentMessages', async () => {
      await adapter.send(makePayload());
      const m1 = adapter.getSentMessages();
      const m2 = adapter.getSentMessages();

      expect(m1).not.toBe(m2);
      expect(m1).toEqual(m2);
    });

    it('should use custom sendSms transport when provided', async () => {
      const calls: { to: string; body: string; from: string }[] = [];
      const customAdapter = new SmsNotificationAdapter({
        sendSms: async (to, body, from) => {
          calls.push({ to, body, from });
          return true;
        },
      });

      const payload = makePayload();
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(true);
      expect(calls).toHaveLength(1);
      expect(calls[0]!.to).toBe('+15551234567');
      expect(calls[0]!.body).toContain('Order Confirmation');
    });

    it('should return failure when sendSms returns false', async () => {
      const customAdapter = new SmsNotificationAdapter({
        sendSms: async () => false,
      });

      const payload = makePayload();
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMS send failed');
    });

    it('should handle sendSms throwing an error', async () => {
      const customAdapter = new SmsNotificationAdapter({
        sendSms: async () => { throw new Error('Network timeout'); },
      });

      const payload = makePayload();
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
    });
  });
});

